#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

int t,num[N];
queue<int> q[1010];

int main(){
    int T=0;
    while(1){
        scanf("%d",&t);
        if(!t) break;
        T++;
        printf("Scenario #%d\n",T);
        while(q[0].size())
            q[0].pop();
        for(int i=1;i<=t;i++){
            while(q[i].size())
                q[i].pop();
            int k,x;
            scanf("%d",&k);
            while(k--){
                scanf("%d",&x);
                num[x]=i;
            }
        }
        while(1){
            char s[10];
            int x;
            scanf("%s",&s);
            if(s[0]=='E'){
                scanf("%d",&x);
                if(q[num[x]].empty())
                    q[0].push(num[x]);
                q[num[x]].push(x);
            }else if(s[0]=='D'){
                x=q[0].front();
                printf("%d\n",q[x].front());
                q[x].pop();
                if(q[x].empty())
                    q[0].pop();
            }else
                break;
        }
        puts("");
    }
    return 0;
}
